async () => {
  const out={url:location.href}; const wait=(ms)=>new Promise(r=>setTimeout(r,ms));
  let lcp=null,cls=0,clsS=[],lt=[],ltt=0;
  try{new PerformanceObserver(l=>{const e=l.getEntries();if(e.length)lcp=e[e.length-1];}).observe({type:'largest-contentful-paint',buffered:true});}catch(e){}
  try{new PerformanceObserver(l=>{for(const e of l.getEntries()){if(!e.hadRecentInput){cls+=e.value;if(e.sources)for(const s of e.sources){if(s.node)clsS.push({val:+e.value.toFixed(4),node:(s.node.tagName||'')+'.'+((s.node.className&&s.node.className.toString)?s.node.className.toString().slice(0,40):'')});}}}}).observe({type:'layout-shift',buffered:true});}catch(e){}
  try{new PerformanceObserver(l=>{for(const e of l.getEntries()){lt.push(Math.round(e.duration));ltt+=e.duration;}}).observe({type:'longtask',buffered:true});}catch(e){}
  await wait(700);
  try{if(lcp){const el=lcp.element;out.lcp={time:Math.round(lcp.renderTime||lcp.loadTime||lcp.startTime),size:Math.round(lcp.size),url:lcp.url||null,el:el?{tag:el.tagName,cls:(el.className&&el.className.toString)?el.className.toString().slice(0,60):null}:null};if(el&&el.tagName==='IMG'){out.lcp.img={loading:el.getAttribute('loading'),fetchpriority:el.getAttribute('fetchpriority'),sizes:el.getAttribute('sizes'),hasSrcset:!!el.getAttribute('srcset'),currentSrc:(el.currentSrc||'').slice(0,150),naturalW:el.naturalWidth,naturalH:el.naturalHeight,clientW:el.clientWidth,clientH:el.clientHeight};}}}catch(e){out.lcpErr=String(e);}
  out.cls=+cls.toFixed(4);out.clsTop=clsS.sort((a,b)=>b.val-a.val).slice(0,4);out.longtask={count:lt.length,totalMs:Math.round(ltt)};
  try{const f=performance.getEntriesByType('paint').find(p=>p.name==='first-contentful-paint');out.fcp=f?Math.round(f.startTime):null;}catch(e){}
  try{const n=performance.getEntriesByType('navigation')[0];if(n)out.nav={ttfb:Math.round(n.responseStart),dcl:Math.round(n.domContentLoadedEventEnd),load:Math.round(n.loadEventEnd),transferKB:Math.round((n.transferSize||0)/1024)};}catch(e){}
  try{const rs=performance.getEntriesByType('resource');const agg={};let imgs=[];for(const r of rs){const t=r.initiatorType||'other';agg[t]=agg[t]||{n:0,kb:0};agg[t].n++;agg[t].kb+=Math.round((r.transferSize||0)/1024);if(t==='img'||/\.(jpg|jpeg|png|webp|avif)(\?|$)/i.test(r.name))imgs.push({u:r.name.slice(0,110),kb:Math.round((r.transferSize||0)/1024)});}out.res=agg;out.topImgs=imgs.sort((a,b)=>b.kb-a.kb).slice(0,6);}catch(e){}
  try{const vh=innerHeight;let lz=0,atf=0;document.querySelectorAll('img').forEach(im=>{const r=im.getBoundingClientRect();if(r.top<vh&&r.bottom>0){atf++;if(im.getAttribute('loading')==='lazy')lz++;}});out.atfImgs={total:atf,lazy:lz};}catch(e){}
  try{const jd=document.querySelector('[class*="jdgm"],[id*="judgeme"],[class*="judgeme"]');out.judgeme=jd?{found:true,h:jd.offsetHeight,minH:getComputedStyle(jd).minHeight}:{found:false};}catch(e){}
  try{let b=[];document.querySelectorAll('head script[src]').forEach(s=>{if(!s.async&&!s.defer&&s.type!=='module'){try{b.push(new URL(s.src).host);}catch(_){}}});out.scripts={headBlocking:b.length,blockingHosts:[...new Set(b)].slice(0,8),totalSrc:document.querySelectorAll('script[src]').length};}catch(e){}
  try{out.cssHeadLinks=document.querySelectorAll('head link[rel="stylesheet"]').length;}catch(e){}
  try{let p=[];document.querySelectorAll('link[rel="preload"]').forEach(l=>p.push((l.getAttribute('as')||'')+':'+(l.getAttribute('href')||'').slice(0,55)));out.preloads=p.slice(0,8);}catch(e){}
  try{const c=document.querySelector('link[rel="canonical"]'),m=document.querySelector('meta[name="description"]'),rb=document.querySelector('meta[name="robots"]'),vp=document.querySelector('meta[name="viewport"]');out.seo={canonical:c?c.href:null,title:document.title,titleLen:document.title.length,descLen:m?(m.content||'').length:0,robots:rb?rb.content:null,viewport:vp?vp.content:null};}catch(e){}
  try{let ty=[],pr=null;document.querySelectorAll('script[type="application/ld+json"]').forEach(s=>{try{let j=JSON.parse(s.textContent);const a=Array.isArray(j)?j:(j['@graph']?j['@graph']:[j]);a.forEach(o=>{if(o&&o['@type']){ty.push(o['@type']);if((''+o['@type']).includes('Product'))pr={offers:!!o.offers,aggregateRating:!!o.aggregateRating};}});}catch(_){}});out.jsonld={types:ty,product:pr};}catch(e){}
  return out;
}
